parameters.jsCode:
// n8n Code node (JavaScript)
// Processes ALL incoming items.
// Each item has .json.text which is either:
// - a JSON object/array,
// - a JSON string,
// - or a plain string.
// Output: for each input item, return ONLY the cleaned structure (or cleaned text).

function removeLinksAndClean(str) {
  if (typeof str !== "string") return str;

  // Keep markdown label, remove URL: [label](url) -> label
  str = str.replace(/\[([^\]]+)\]\(([^)]+)\)/g, "$1");

  // Remove URLs and domains
  str = str
    .replace(/\bhttps?:\/\/[^\s<>()]+/gi, "")
    .replace(/\bwww\.[^\s<>()]+/gi, "")
    .replace(/\b(?:[a-z0-9-]+\.)+[a-z]{2,}(?:\/[^\s<>()]*)?/gi, "");

  // Whitespace cleanup
  return str
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

function deepCleanTextFields(node) {
  if (Array.isArray(node)) {
    return node.map(deepCleanTextFields);
  }

  if (node && typeof node === "object") {
    const out = {};
    for (const [key, value] of Object.entries(node)) {
      if (key === "text" && typeof value === "string") {
        out[key] = removeLinksAndClean(value);
      } else {
        out[key] = deepCleanTextFields(value);
      }
    }
    return out;
  }

  // primitives (string/number/bool/null)
  return node;
}

function cleanOne(raw) {
  // raw is item.json.text
  if (typeof raw === "string") {
    // Try JSON parse first
    try {
      const parsed = JSON.parse(raw);
      return deepCleanTextFields(parsed);
    } catch (e) {
      // Plain string -> just clean it
      return { text: removeLinksAndClean(raw) };
    }
  }

  // Already object/array
  return deepCleanTextFields(raw);
}

// Process all input items
const items = $input.all();

return items.map((item) => {
  const raw = item?.json?.text;
  const cleaned = cleanOne(raw);

  // IMPORTANT: output ONLY the cleaned content (no other original fields)
  return { json: cleaned };
});
